  ('aboriginal-57f41407-moex-00410', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依據原住民族語言發展法之規定，直轄市、縣（市）政府、原住民族地區及原住民人口多少人以上之 非原住民族地區之鄉（鎮、市、區）公所，應置專職原住民族語言推廣人員？', '["500人", "1,000人", "1,500人", "3,000人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
